import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody
import okhttp3.MediaType.Companion.toMediaTypeOrNull

class HttpClient {

    private val client = OkHttpClient()

    fun performHttpGetRequest(url: String): String? {
        val request = Request.Builder()
            .url(url)
            .build()

        client.newCall(request).execute().use { response ->
            return if (response.isSuccessful) {
                response.body?.string() 
            } else {
                null
            }
        }
    }

    fun performHttpPostRequest(url: String, json: String): String? {
        val requestBody = RequestBody.create(json.toMediaTypeOrNull("application/json; charset=utf-8"), json)

        val request = Request.Builder()
            .url(url)
            .post(requestBody)
            .build()

        client.newCall(request).execute().use { response ->
            return if (response.isSuccessful) {
                response.body?.string()
            } else {
                null
            }
        }
    }
}
The above is a simplified OkHttp-based HTTP client in Kotlin for Android. It supports both HTTP and HTTPS and communication with both IoT devices on local networks and cloud APIs.